/**
 * Classifica o tipo de sinistro, monta orientações imediatas e gera
 * um número de sinistro determinístico (sinistro por dia + conversa).
 */

function __hashHex(input) {
  // Substitui o hash SHA-256 do node crypto.
  // Módulo 'crypto' é bloqueado no task-runner do n8n, então fazemos
  // um hash determinístico em JS puro (8x FNV-1a concatenados = 64 hex chars).
  const str = String(input);
  const seeds = [0x811c9dc5, 0xcbf29ce4, 0xdeadbeef, 0xcafebabe,
                 0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a];
  let out = '';
  for (let round = 0; round < 8; round++) {
    let h = seeds[round];
    for (let i = 0; i < str.length; i++) {
      h ^= str.charCodeAt(i) + round;
      h = Math.imul(h, 0x01000193) >>> 0;
    }
    out += h.toString(16).padStart(8, '0');
  }
  return out;
}
const input = $input.first().json;
const tipo = String(input.tipo_sinistro || 'outros').toLowerCase();
const nome = input.nome || '';

const orientacoes = {
  vazamento: [
    'Primeiro: feche o registro de água se ainda estiver vazando.',
    'Tire **foto de tudo** antes de mexer: teto, parede, piso, móveis atingidos.',
    'Guarde qualquer recibo de conserto emergencial (chaveiro, encanador, etc).',
    'Não jogue nada fora até o corretor avaliar.'
  ],
  incendio: [
    'Prioridade agora é segurança: se ainda tiver fogo, 193.',
    'Quando seguro, **não mexa no local**: a seguradora precisa inspecionar.',
    'Tire fotos de longe do cômodo afetado.',
    'Guarde todos os documentos que sobraram (notas fiscais, manuais).'
  ],
  colisao: [
    'Se teve vítima: 190 ou 193 **antes de qualquer coisa**.',
    'Faça o **Boletim de Ocorrência** (pode ser online em boa parte dos estados).',
    'Tire fotos de todos os ângulos dos veículos, placas, rua, semáforos.',
    'Pegue nome, telefone, seguradora e placa do outro motorista.',
    '**Não aceite acordo na hora**: deixe a seguradora avaliar.'
  ],
  roubo: [
    'BO imediato na delegacia (ou online, se o seu estado permitir).',
    'Liste o que foi levado — se possível com notas fiscais ou fotos antigas.',
    'Não limpe o local se houve arrombamento: perícia pode ser necessária.'
  ],
  morte: [
    'Meus sentimentos. Vou te guiar com calma.',
    'A seguradora vai pedir: **certidão de óbito**, CPF e comprovante de residência do falecido, documentos dos beneficiários listados na apólice.',
    'Se foi morte natural: relatório médico ou atestado com a causa.',
    'Se foi acidente: **Boletim de Ocorrência** e laudo do IML.',
    'Guarde tudo junto: a equipe humana vai te ajudar a organizar o processo.'
  ],
  invalidez: [
    'Junte **todos os laudos médicos** e exames, do início até agora.',
    'O médico precisa emitir um relatório com **CID** e grau de invalidez.',
    'Se foi por acidente: BO e laudos do pronto-socorro inicial.',
    'A perícia da seguradora vai ser presencial — eu vou te avisar a data.'
  ],
  doenca_grave: [
    'Precisamos do **diagnóstico formal** (CID no relatório médico).',
    'Junte todos os exames que comprovam: biópsia, ressonância, sangue, o que houver.',
    'O pedido é feito com toda essa documentação; a seguradora costuma pedir parecer de um segundo médico.'
  ]
};

function matchTipo(t) {
  for (const key of Object.keys(orientacoes)) {
    if (t.includes(key)) return key;
  }
  return 'outros';
}
const key = matchTipo(tipo);
const passos = orientacoes[key] || [
  'Vou te ajudar agora. Enquanto um corretor humano assume, me manda o máximo de informação: o que aconteceu, data, local, e qualquer foto que tiver.'
];

const seedStr = `${input.conversation_id}|${key}|${DateTime.now().toFormat('yyyy-MM-dd')}`;
const hash = __hashHex(seedStr);
const numeroSinistro = `SIN-${hash.slice(0, 10).toUpperCase()}`;

const orientacoesTexto = passos.map(p => `• ${p}`).join('\n');
const resumoCliente = `Entendi, ${nome ? nome + ', ' : ''}pode respirar — registrei aqui como sinistro *${numeroSinistro}* e vou te orientar agora.\n\n` +
  `*Passos imediatos:*\n${orientacoesTexto}\n\n` +
  `Um corretor da equipe já foi avisado e vai assumir daqui a pouco para conduzir a abertura junto à seguradora. Fica tranquilo que você não está sozinho.`;

const tituloTarefa = `Sinistro ${key} - ${nome || 'sem nome'} (${numeroSinistro})`;
const descricaoTarefa = [
  `🚨 *Sinistro: ${numeroSinistro}*`,
  `Tipo: ${key}`,
  `Aberto em: ${DateTime.now().toISO()}`,
  `Cliente: ${nome || 'não informado'} · ${input.telefone || 'sem telefone'}`,
  '',
  `*Relato do cliente:*`,
  input.descricao_cliente || '(não informado)',
  '',
  `*Orientações imediatas enviadas ao cliente:*`,
  ...passos.map(p => `- ${p}`)
].join('\n');

const resumoConversa = `Cliente acionou sinistro ${key.toUpperCase()}. Número: ${numeroSinistro}. Relato: ${input.descricao_cliente || '(sem texto)'}. Orientações iniciais já enviadas, card criado no funil Sinistros.`;

return [{
  json: {
    account_id: input.account_id,
    conversation_id: input.conversation_id,
    inbox_id: input.inbox_id,
    tipo_sinistro: key,
    numero_sinistro: numeroSinistro,
    nome,
    telefone: input.telefone,
    titulo_tarefa: tituloTarefa,
    descricao_tarefa: descricaoTarefa,
    resumo_cliente: resumoCliente,
    resumo_conversa: resumoConversa
  }
}];

/**
 * Acha o board de Sinistros e a etapa "Aberto" dentro dele.
 * O node kanbanBoard.list do @fazer-ai/n8n-nodes-chatwoot emite um item
 * por board (já desempacotado), então usamos $input.all() para juntá-los.
 */
const boards = $input.all().map(i => i.json);

if (boards.length === 0) {
  throw new Error('kanbanBoard.list não retornou boards. Rode o WF 00 Configurações.');
}

const sinistroBoard = boards.find(b => String(b.name || '').toLowerCase() === 'sinistros');
if (!sinistroBoard) {
  throw new Error('Funil "Sinistros" não encontrado. Rode o WF 00 Configurações.');
}

// Tenta encontrar as etapas dentro do board
const steps = sinistroBoard.steps_summary ?? sinistroBoard.steps ?? sinistroBoard.board_steps ?? [];
if (!steps.length) {
  throw new Error('Funil Sinistros encontrado mas sem etapas. Rode o WF 00 Configurações.');
}
const abertoStep = steps.find(s => String(s.name || '').toLowerCase() === 'aberto');
if (!abertoStep) {
  throw new Error('Etapa "Aberto" não encontrada no funil Sinistros.');
}

const m = $('Classificar sinistro').first().json;

return [{
  json: {
    ...m,
    board_id: sinistroBoard.id,
    step_id: abertoStep.id
  }
}];
